INSERT INTO skills (slug,title,tagline,description,category,subcategory,tags,difficulty,price_inr,price_usd,is_free,steps,video_url,video_thumbnail,trending_score,view_count,purchase_count,is_trending,is_new,is_featured,pack_id,published) VALUES (
'prompt-optimizer','Prompt Optimizer','Turn vague prompts into precise, high-output instructions','Master the art of prompt engineering with a repeatable 4-step framework. Identify task type, add role context, include few-shot examples, and validate with temperature 0.','ai-llm',NULL,
ARRAY['prompting','llm','productivity'],'beginner',0,0,true,
'[{"number":1,"title":"Identify the task type","description":"Classify your task as one of four core types before writing any prompt.","code":"const taskTypes = [\"classify\",\"generate\",\"extract\",\"reason\"] as const;","language":"typescript"},{"number":2,"title":"Add role and context prefix","description":"Prepend a role and context block to every prompt for consistent output.","code":"const optimized = `You are an expert {role}. Context: {context}\\nTask: {task}\\nOutput format: {format}`;","language":"typescript"},{"number":3,"title":"Add few-shot examples","description":"Include 2-3 examples so the model learns the exact output style you need.","code":"// Add 2-3 examples in your prompt\\n// Input: \"summarize this\" → Output: \"Create a 3-bullet executive summary...\"","language":"typescript"},{"number":4,"title":"Test with temperature 0","description":"Always validate a new prompt deterministically before using it in production.","code":"const res = await model.generateContent({contents:[{role:\"user\",parts:[{text:prompt}]}],generationConfig:{temperature:0}});","language":"typescript"}]'::jsonb,
NULL,NULL,900,0,0,true,true,true,NULL,true);

INSERT INTO skills (slug,title,tagline,description,category,subcategory,tags,difficulty,price_inr,price_usd,is_free,steps,video_url,video_thumbnail,trending_score,view_count,purchase_count,is_trending,is_new,is_featured,pack_id,published) VALUES (
'rag-pipeline-builder','RAG Pipeline Builder','Build retrieval-augmented generation from scratch in 30 min','Learn to chunk documents, generate embeddings, store them in Qdrant, and retrieve context to ground LLM answers in real knowledge.','ai-llm',NULL,
ARRAY['rag','vector-db','embeddings'],'intermediate',199900,1900,false,
'[{"number":1,"title":"Chunk documents","description":"Split source text into overlapping chunks so context is never cut mid-sentence.","code":"function chunkText(text:string,size=512,overlap=50){const chunks=[];for(let i=0;i<text.length;i+=size-overlap)chunks.push(text.slice(i,i+size));return chunks;}","language":"typescript"},{"number":2,"title":"Embed chunks via Gemini","description":"Generate a dense vector for each chunk using the text-embedding-004 model.","code":"const model=genAI.getGenerativeModel({model:\"text-embedding-004\"});const {embedding}=await model.embedContent(chunk);","language":"typescript"},{"number":3,"title":"Store in Qdrant","description":"Upsert each chunk with its embedding vector and source metadata.","code":"await client.upsert(collectionName,{points:[{id:uuid(),vector:embedding.values,payload:{text:chunk,source}}]});","language":"typescript"},{"number":4,"title":"Embed question and search","description":"Embed the user query and retrieve the top-5 most relevant chunks.","code":"const qEmbed=await model.embedContent(question);const results=await client.search(collectionName,{vector:qEmbed.embedding.values,limit:5});","language":"typescript"},{"number":5,"title":"Generate grounded answer","description":"Combine retrieved chunks as context and prompt the LLM to answer.","code":"const context=results.map(r=>r.payload.text).join(\"\\n\\n\");const answer=await chat.sendMessage(`Context:\\n${context}\\n\\nQuestion: ${question}`);","language":"typescript"}]'::jsonb,
NULL,NULL,950,0,0,true,true,true,NULL,true);

INSERT INTO skills (slug,title,tagline,description,category,subcategory,tags,difficulty,price_inr,price_usd,is_free,steps,video_url,video_thumbnail,trending_score,view_count,purchase_count,is_trending,is_new,is_featured,pack_id,published) VALUES (
'agent-workflow-designer','Agent Workflow Designer','Design multi-step AI agent pipelines with tools and memory','Build production-grade multi-step agent systems using the ReAct loop pattern. Define specialist roles, wire up tools, and add persistent memory.','ai-llm',NULL,
ARRAY['agents','orchestration','llm'],'advanced',299900,2900,false,
'[{"number":1,"title":"Define agent roles","description":"Type each agent with a name, role description, allowed tools, and model tier.","code":"type Agent={name:string;role:string;tools:string[];model:\"flash\"|\"pro\"};","language":"typescript"},{"number":2,"title":"Build tool registry","description":"Register callable tools the agent can invoke during its reasoning loop.","code":"const tools={search:async(q:string)=>fetch(`/api/search?q=${q}`).then(r=>r.json()),calculator:(expr:string)=>eval(expr)};","language":"typescript"},{"number":3,"title":"Implement ReAct loop","description":"Alternate Thought → Action → Observation until the task is complete.","code":"while(!done){const thought=await llm.think(state);const action=await llm.act(thought);const obs=await tools[action.tool](action.input);state.observations.push(obs);}","language":"typescript"},{"number":4,"title":"Add memory store","description":"Persist facts per agent so later steps can reference earlier observations.","code":"const memory=new Map<string,string[]>();function remember(agent:string,fact:string){memory.get(agent)?.push(fact)??memory.set(agent,[fact]);}","language":"typescript"}]'::jsonb,
NULL,NULL,880,0,0,true,true,false,NULL,true);

INSERT INTO skills (slug,title,tagline,description,category,subcategory,tags,difficulty,price_inr,price_usd,is_free,steps,video_url,video_thumbnail,trending_score,view_count,purchase_count,is_trending,is_new,is_featured,pack_id,published) VALUES (
'vector-db-schema-designer','Vector DB Schema Designer','Design Qdrant/Pinecone collections for production RAG workloads','Learn the right payload schema, collection config, named vectors for hybrid search, and payload indexes for lightning-fast filtered retrieval.','ai-llm',NULL,
ARRAY['qdrant','pinecone','vector-db'],'intermediate',99900,900,false,
'[{"number":1,"title":"Define payload schema","description":"Type your payload upfront so every chunk has consistent filterable metadata.","code":"interface VectorPayload{id:string;text:string;source:string;chunk_index:number;metadata:Record<string,unknown>;}","language":"typescript"},{"number":2,"title":"Create Qdrant collection","description":"Create a collection with Cosine distance and tuned segment count.","code":"await client.createCollection(\"docs\",{vectors:{size:768,distance:\"Cosine\"},optimizersConfig:{defaultSegmentNumber:2}});","language":"typescript"},{"number":3,"title":"Add named vectors for hybrid search","description":"Store both dense and sparse vectors in the same point for hybrid retrieval.","code":"await client.createCollection(\"docs\",{vectors:{dense:{size:768,distance:\"Cosine\"},sparse:{size:0,distance:\"Dot\"}}});","language":"typescript"},{"number":4,"title":"Set up payload index for filtering","description":"Index keyword fields so Qdrant can filter before computing vector similarity.","code":"await client.createPayloadIndex(\"docs\",{fieldName:\"source\",fieldSchema:\"keyword\"});","language":"typescript"}]'::jsonb,
NULL,NULL,720,0,0,true,true,false,NULL,true);

INSERT INTO skills (slug,title,tagline,description,category,subcategory,tags,difficulty,price_inr,price_usd,is_free,steps,video_url,video_thumbnail,trending_score,view_count,purchase_count,is_trending,is_new,is_featured,pack_id,published) VALUES (
'llm-cost-optimizer','LLM Cost Optimizer','Cut your AI API bill by 60–80% with smart routing and caching','Use MD5 caching for repeated queries, complexity-based model routing, request batching, and spend tracking to slash your LLM costs.','ai-llm',NULL,
ARRAY['cost','optimization','caching'],'intermediate',199900,1900,false,
'[{"number":1,"title":"Cache repeated queries","description":"Hash prompts with MD5 and serve cached responses before hitting the API.","code":"const cache=new Map<string,string>();async function cachedLLM(prompt:string){const key=crypto.createHash(\"md5\").update(prompt).digest(\"hex\");if(cache.has(key))return cache.get(key)!;const res=await llm(prompt);cache.set(key,res);return res;}","language":"typescript"},{"number":2,"title":"Route by complexity","description":"Send short, simple prompts to flash and only send complex analysis to pro.","code":"function routeModel(prompt:string):\"flash\"|\"pro\"{const tokens=prompt.split(\" \").length;return tokens<200&&!prompt.includes(\"analyze\")?\"flash\":\"pro\";}","language":"typescript"},{"number":3,"title":"Batch requests","description":"Queue prompts and flush in batches of 10 every 100ms to reduce overhead.","code":"const queue:Array<{prompt:string;resolve:(v:string)=>void}>=[];setInterval(async()=>{if(!queue.length)return;const batch=queue.splice(0,10);const results=await Promise.all(batch.map(b=>llm(b.prompt)));batch.forEach((b,i)=>b.resolve(results[i]!));},100);","language":"typescript"},{"number":4,"title":"Track spend per model","description":"Accumulate token costs per model tier so you can set budget alerts.","code":"const spend={flash:0,pro:0};function trackTokens(model:string,tokens:number){if(model===\"flash\")spend.flash+=tokens*0.000075/1000;else spend.pro+=tokens*0.00150/1000;}","language":"typescript"}]'::jsonb,
NULL,NULL,860,0,0,true,true,false,NULL,true);

INSERT INTO skills (slug,title,tagline,description,category,subcategory,tags,difficulty,price_inr,price_usd,is_free,steps,video_url,video_thumbnail,trending_score,view_count,purchase_count,is_trending,is_new,is_featured,pack_id,published) VALUES (
'semantic-search-builder','Semantic Search Builder','Add AI-powered semantic search to any app in under 2 hours','Index your content as embeddings, expose a /search endpoint, and blend keyword and vector results for best-of-both recall.','ai-llm',NULL,
ARRAY['search','embeddings','nlp'],'intermediate',199900,1900,false,
'[{"number":1,"title":"Index your content","description":"Embed every document and collect id, text, and vector together.","code":"async function indexDocuments(docs:string[]){const embeddings=await Promise.all(docs.map(d=>embed(d)));return embeddings.map((e,i)=>({id:i,text:docs[i],vector:e}));}","language":"typescript"},{"number":2,"title":"Store with metadata","description":"Upsert points into Qdrant with the raw text in the payload for display.","code":"await qdrant.upsert(\"search\",{points:indexed.map(d=>({id:d.id,vector:d.vector,payload:{text:d.text}}))});","language":"typescript"},{"number":3,"title":"Query endpoint","description":"Expose a GET /search route that embeds the query and returns top hits.","code":"app.get(\"/search\",async(req,res)=>{const q=req.query.q as string;const qVec=await embed(q);const hits=await qdrant.search(\"search\",{vector:qVec,limit:10});res.json(hits);});","language":"typescript"},{"number":4,"title":"Hybrid keyword and semantic merge","description":"Merge Fuse.js keyword hits with vector hits and deduplicate to top 10.","code":"const keywordHits=fuse.search(query).map(r=>r.item);const semanticHits=await vectorSearch(query);const merged=[...new Set([...keywordHits,...semanticHits])].slice(0,10);","language":"typescript"}]'::jsonb,
NULL,NULL,790,0,0,true,true,false,NULL,true);

