ARRAY['fine-tuning','dataset','training'],'advanced',299900,2900,false,
'[{"number":1,"title":"Generate Q&A pairs from docs","description":"Prompt an LLM to produce structured Q&A pairs from each source document.","code":"async function generateQA(doc:string){const res=await llm(`Generate 5 Q&A pairs from:\\n${doc}\\nFormat: [{\"q\":\"...\",\"a\":\"...\"}]`);return JSON.parse(res);}","language":"typescript"},{"number":2,"title":"Augment with paraphrasing","description":"Generate n rephrasings of each question to increase dataset diversity.","code":"async function paraphrase(text:string,n=3){return Promise.all(Array(n).fill(0).map(()=>llm(`Rephrase: ${text}`)));}","language":"typescript"},{"number":3,"title":"Format for fine-tuning","description":"Convert pairs to the messages format expected by Gemini and OpenAI fine-tune endpoints.","code":"const formatted=pairs.map(p=>({messages:[{role:\"user\",content:p.q},{role:\"assistant\",content:p.a}]}));","language":"typescript"},{"number":4,"title":"Validate and filter quality","description":"Score each pair 1-10 and keep only those rated 7 or above.","code":"const scores=await Promise.all(pairs.map(p=>llm(`Rate 1-10 quality of: Q:${p.q} A:${p.a}. Reply with just a number.`)));const filtered=pairs.filter((_,i)=>parseInt(scores[i]!)>=7);","language":"typescript"}]'::jsonb,
