ARRAY['chatbot','persona','prompt'],'beginner',0,0,true,
'[{"number":1,"title":"Define core traits","description":"Capture name, tone, vocabulary level, response length, and explicit avoids in a typed object.","code":"const persona={name:\"Aria\",tone:\"friendly-professional\",vocabulary:\"simple\",responseLength:\"concise\",avoids:[\"jargon\",\"negativity\"],always:[\"acknowledge first\",\"offer next step\"]};","language":"typescript"},{"number":2,"title":"Write system prompt","description":"Serialize the persona object into a natural-language system prompt.","code":"const systemPrompt=`You are ${persona.name}. Tone: ${persona.tone}. Always ${persona.always.join(\" and \")}. Never ${persona.avoids.join(\" or \")}.`;","language":"typescript"},{"number":3,"title":"Test edge cases","description":"Run the persona against rude, off-topic, competitor, and pricing-pressure inputs.","code":"const edgeCases=[\"rude question\",\"off-topic request\",\"competitor mention\",\"pricing pressure\"];for(const c of edgeCases)console.log(await chat(systemPrompt,c));","language":"typescript"},{"number":4,"title":"Add escalation logic","description":"Detect negative sentiment or explicit human requests and route to a live agent.","code":"if(sentiment(response)<-0.5||response.includes(\"speak to human\"))escalate(userId);","language":"typescript"}]'::jsonb,
