INSERT INTO skills (slug,title,tagline,description,category,subcategory,tags,difficulty,price_inr,price_usd,is_free,steps,video_url,video_thumbnail,trending_score,view_count,purchase_count,is_trending,is_new,is_featured,pack_id,published) VALUES (
'multi-agent-orchestrator','Multi-Agent Orchestrator','Coordinate specialized AI agents to solve complex multi-step tasks','Define researcher, writer, and reviewer agents, build an LLM-powered router, pass context between agents, and handle failures with exponential backoff retry.','ai-llm',NULL,
ARRAY['agents','orchestration','automation'],'advanced',299900,2900,false,
'[{"number":1,"title":"Define specialist agents","description":"Give each agent a focused system prompt, output contract, and model tier.","code":"const agents={researcher:{prompt:\"You research topics. Return structured JSON findings.\",model:\"pro\"},writer:{prompt:\"You write content from research. Return markdown.\",model:\"flash\"},reviewer:{prompt:\"You review and score content 1-10 with fixes.\",model:\"pro\"}};","language":"typescript"},{"number":2,"title":"Build routing logic","description":"Use an orchestrator LLM to decompose the task into an ordered plan.","code":"async function route(task:string):Promise<string>{const plan=await orchestrator(`Break into steps: ${task}\\nAgents: researcher,writer,reviewer\\nReturn: [{\"agent\":\"...\",\"input\":\"...\"}]`);return JSON.parse(plan);}","language":"typescript"},{"number":3,"title":"Pass context between agents","description":"Accumulate each agent output into a shared context object for downstream steps.","code":"let context={};for(const step of plan){const agent=agents[step.agent];const result=await runAgent(agent,{...step.input,context});context={...context,[step.agent]:result};}","language":"typescript"},{"number":4,"title":"Handle failures with retry","description":"Wrap each agent call with exponential backoff so transient errors do not fail the whole pipeline.","code":"async function runWithRetry(agent:Agent,input:unknown,retries=3){for(let i=0;i<retries;i++){try{return await run(agent,input)}catch(e){if(i===retries-1)throw e;await sleep(1000*2**i);}}}","language":"typescript"}]'::jsonb,
NULL,NULL,920,0,0,true,true,true,NULL,true);

