'[{"number":1,"title":"Input your niche and problem","description":"Define the industry, specific pain point, target user, and budget constraint.","code":"const input={industry:\"healthcare\",painPoint:\"appointment scheduling\",targetUser:\"clinic owner\",budget:\"under $100/mo\"};","language":"typescript"},{"number":2,"title":"Generate 10 ideas","description":"Prompt the LLM to produce structured ideas with name, problem, user, monetization, and build time.","code":"const ideas=await llm(`Generate 10 AI product ideas for: ${JSON.stringify(input)}\\nFor each: name, problem solved, target user, monetization, build time. JSON array.`);","language":"typescript"},{"number":3,"title":"Score by feasibility","description":"Have the model score each idea across four dimensions and rank the list.","code":"const scored=await llm(`Score each idea 1-10 for: market size, technical feasibility, competition, monetization. Input: ${ideas}`);","language":"typescript"},{"number":4,"title":"Validate top ideas","description":"Pull real search volume and competitor data for the top 3 before committing.","code":"const top3=scored.slice(0,3);for(const idea of top3){const keywords=await getSearchVolume(idea.name);const competitors=await searchCompetitors(idea.name);console.log({idea,keywords,competitors});}","language":"typescript"}]'::jsonb,
