'[{"number":1,"title":"Map current workflow","description":"Model the existing manual process as a trigger plus ordered steps with a timeout budget.","code":"const workflow={trigger:\"new_email\",steps:[\"classify_intent\",\"extract_data\",\"lookup_crm\",\"draft_reply\",\"queue_review\"],timeout_ms:30000};","language":"typescript"},{"number":2,"title":"Build trigger handler","description":"Accept the triggering event via webhook and enqueue it for processing.","code":"app.post(\"/webhook/email\",async(req,res)=>{const email=req.body;const job=await queue.add(\"process-email\",email);res.json({jobId:job.id});});","language":"typescript"},{"number":3,"title":"Implement each step as agent","description":"Map each step name to an async AI function that transforms the data.","code":"const steps={classify_intent:async(email:Email)=>llm(`Classify: ${email.subject}\\n${email.body}\\nReturn: sales|support|spam|other`),extract_data:async(email:Email)=>llm(`Extract JSON: name,company,phone from:\\n${email.body}`)};","language":"typescript"},{"number":4,"title":"Chain with error handling","description":"Run steps sequentially, notify Slack on failure, and break the chain cleanly.","code":"for(const stepName of workflow.steps){try{result=await steps[stepName](result);}catch(e){await notify(\"slack\",`Step ${stepName} failed: ${e}`);break;}}","language":"typescript"}]'::jsonb,
