'esp32-firmware-scaffold','ESP32 Firmware Scaffold','Production-ready ESP32 project: OTA, WiFi manager, MQTT, NVS','Scaffold a full PlatformIO project with WiFiManager for zero-touch provisioning, PubSubClient MQTT, ElegantOTA for remote updates, and a 5-second sensor publish loop.','iot',NULL,
ARRAY['esp32','firmware','arduino'],'intermediate',299900,2900,false,
'[{"number":1,"title":"Project structure","description":"Create the PlatformIO directory layout with feature-separated source folders.","code":"mkdir my-esp32 && cd my-esp32\nmkdir -p src/{wifi,mqtt,sensors,ota} include\ntouch platformio.ini src/main.cpp","language":"bash"},{"number":2,"title":"platformio.ini","description":"Configure the board, framework, and key library dependencies.","code":"[env:esp32dev]\nplatform=espressif32\nboard=esp32dev\nframework=arduino\nlib_deps =\n  knolleary/PubSubClient@^2.8\n  tzapu/WiFiManager@^2.0\n  ayushsharma82/ElegantOTA@^3.1","language":"ini"},{"number":3,"title":"WiFi and MQTT init","description":"Use WiFiManager for captive-portal provisioning then connect MQTT with the chip MAC as client ID.","code":"WiFiManager wm;\nwm.autoConnect(\"ESP32-Setup\");\nMQTTClient mqtt;\nmqtt.begin(\"broker.mqtt.io\",net);\nmqtt.connect(\"device-\"+String(ESP.getEfuseMac()));","language":"cpp"},{"number":4,"title":"OTA update handler","description":"Register ElegantOTA with auto-reboot and hook start/end callbacks for logging.","code":"ElegantOTA.begin(&server);\nElegantOTA.setAutoReboot(true);\nElegantOTA.onStart([](){Serial.println(\"OTA start\");});\nElegantOTA.onEnd([](){Serial.println(\"OTA done\");});","language":"cpp"},{"number":5,"title":"Sensor read loop","description":"Poll the DHT sensor every 5 seconds and publish temperature over MQTT.","code":"void loop(){\n  ElegantOTA.loop();\n  mqtt.loop();\n  if(millis()-lastRead>5000){\n    float t=dht.readTemperature();\n    mqtt.publish(\"/sensors/temp\",String(t));\n    lastRead=millis();\n  }\n}","language":"cpp"}]'::jsonb,
NULL,NULL,880,0,0,true,true,true,NULL,true);

INSERT INTO skills (slug,title,tagline,description,category,subcategory,tags,difficulty,price_inr,price_usd,is_free,steps,video_url,video_thumbnail,trending_score,view_count,purchase_count,is_trending,is_new,is_featured,pack_id,published) VALUES (
'mqtt-broker-config','MQTT Broker Config','Production Mosquitto/EMQX setup with TLS, auth and ACLs','Install Mosquitto, configure TLS on port 8883, add password auth with per-device ACLs, then verify with publish and subscribe test commands.','iot',NULL,
ARRAY['mqtt','mosquitto','emqx'],'intermediate',199900,1900,false,
'[{"number":1,"title":"Install Mosquitto","description":"Install and enable the Mosquitto broker on a Debian/Ubuntu server.","code":"sudo apt update && sudo apt install -y mosquitto mosquitto-clients\nsudo systemctl enable mosquitto","language":"bash"},{"number":2,"title":"TLS config","description":"Create the TLS listener config file with CA, cert, and key paths.","code":"# /etc/mosquitto/conf.d/tls.conf\nlistener 8883\ncafile /etc/mosquitto/certs/ca.crt\ncertfile /etc/mosquitto/certs/server.crt\nkeyfile /etc/mosquitto/certs/server.key\nrequire_certificate false","language":"bash"},{"number":3,"title":"Password auth and ACLs","description":"Create a password file and restrict each device to its own topic subtree.","code":"mosquitto_passwd -c /etc/mosquitto/passwd device1\n# /etc/mosquitto/acl\nuser device1\ntopic read sensors/#\ntopic write sensors/device1/#","language":"bash"},{"number":4,"title":"Test connection","description":"Verify TLS publish and subscribe work end-to-end from the command line.","code":"mosquitto_pub -h localhost -p 8883 --cafile ca.crt -u device1 -P pass1 -t sensors/device1/temp -m 23.5\nmosquitto_sub -h localhost -p 8883 --cafile ca.crt -u device1 -P pass1 -t sensors/#","language":"bash"}]'::jsonb,
NULL,NULL,720,0,0,true,true,false,NULL,true);

INSERT INTO skills (slug,title,tagline,description,category,subcategory,tags,difficulty,price_inr,price_usd,is_free,steps,video_url,video_thumbnail,trending_score,view_count,purchase_count,is_trending,is_new,is_featured,pack_id,published) VALUES (
'ble-gatt-profile-designer','BLE GATT Profile Designer','Design and implement custom BLE GATT profiles for ESP32/nRF52','Define custom service and characteristic UUIDs, create a BLE server with notify and write properties, implement command callbacks, and start advertising.','iot',NULL,
ARRAY['ble','gatt','esp32'],'advanced',299900,2900,false,
'[{"number":1,"title":"Define service UUIDs","description":"Generate and declare unique 128-bit UUIDs for your service and each characteristic.","code":"#define SERVICE_UUID  \"4fafc201-1fb5-459e-8fcc-c5c9c331914b\"\n#define CHAR_TEMP_UUID \"beb5483e-36e1-4688-b7f5-ea07361b26a8\"\n#define CHAR_CMD_UUID  \"d4e0b0f6-3b5e-4b5e-8b5e-4b5e8b5e4b5e\"","language":"cpp"},{"number":2,"title":"Create service and characteristics","description":"Instantiate the GATT server, service, and characteristics with the correct property flags.","code":"BLEServer* server=BLEDevice::createServer();\nBLEService* svc=server->createService(SERVICE_UUID);\nBLECharacteristic* tempChar=svc->createCharacteristic(CHAR_TEMP_UUID,BLECharacteristic::PROPERTY_READ|BLECharacteristic::PROPERTY_NOTIFY);\ntempChar->addDescriptor(new BLE2902());","language":"cpp"},{"number":3,"title":"Implement write callbacks","description":"Subclass BLECharacteristicCallbacks to handle inbound command writes.","code":"class CmdCallbacks: public BLECharacteristicCallbacks{\n  void onWrite(BLECharacteristic* c){\n    std::string v=c->getValue();\n    if(v==\"reboot\")ESP.restart();\n    if(v==\"calibrate\")calibrateSensor();\n  }\n};","language":"cpp"},{"number":4,"title":"Start advertising","description":"Start the service and begin BLE advertising with the service UUID in the scan response.","code":"svc->start();\nBLEAdvertising* adv=BLEDevice::getAdvertising();\nadv->addServiceUUID(SERVICE_UUID);\nadv->setScanResponse(true);\nBLEDevice::startAdvertising();","language":"cpp"}]'::jsonb,
NULL,NULL,650,0,0,true,true,false,NULL,true);

INSERT INTO skills (slug,title,tagline,description,category,subcategory,tags,difficulty,price_inr,price_usd,is_free,steps,video_url,video_thumbnail,trending_score,view_count,purchase_count,is_trending,is_new,is_featured,pack_id,published) VALUES (
'timescaledb-iot-schema','TimescaleDB IoT Schema','Time-series PostgreSQL schema for fleet IoT data at scale','Enable TimescaleDB, create a sensor_readings hypertable, configure 7-day compression and 90-day retention, add continuous hourly aggregates, and build a device registry.','iot',NULL,
ARRAY['timescaledb','postgresql','iot'],'intermediate',199900,1900,false,
'[{"number":1,"title":"Enable extension and create hypertable","description":"Enable TimescaleDB and convert the sensor_readings table to a hypertable partitioned by time.","code":"CREATE EXTENSION IF NOT EXISTS timescaledb;\nCREATE TABLE sensor_readings(\n  time        TIMESTAMPTZ   NOT NULL,\n  device_id   TEXT          NOT NULL,\n  metric      TEXT          NOT NULL,\n  value       DOUBLE PRECISION,\n  tags        JSONB         DEFAULT \"{}\"\n);\nSELECT create_hypertable(''sensor_readings'',''time'');","language":"sql"},{"number":2,"title":"Add compression and retention","description":"Compress chunks older than 7 days and drop chunks older than 90 days automatically.","code":"ALTER TABLE sensor_readings SET(\n  timescaledb.compress,\n  timescaledb.compress_segmentby=''device_id,metric''\n);\nSELECT add_compression_policy(''sensor_readings'',INTERVAL ''7 days'');\nSELECT add_retention_policy(''sensor_readings'',INTERVAL ''90 days'');","language":"sql"},{"number":3,"title":"Continuous aggregates","description":"Create a materialised hourly average view that refreshes automatically.","code":"CREATE MATERIALIZED VIEW hourly_avg WITH(timescaledb.continuous) AS\nSELECT time_bucket(''1 hour'',time) AS hour,device_id,metric,\n  AVG(value) AS avg_val,MAX(value) AS max_val\nFROM sensor_readings GROUP BY 1,2,3;\nSELECT add_continuous_aggregate_policy(''hourly_avg'',\n  start_offset=>''3 hours'',end_offset=>''1 hour'',schedule_interval=>''1 hour'');","language":"sql"},{"number":4,"title":"Device registry table","description":"Create a normalised device registry with location and metadata as JSONB.","code":"CREATE TABLE devices(\n  id               UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n  serial           TEXT UNIQUE NOT NULL,\n  firmware_version TEXT,\n  location         JSONB,\n  last_seen        TIMESTAMPTZ,\n  metadata         JSONB DEFAULT ''{}''\n);","language":"sql"}]'::jsonb,
NULL,NULL,700,0,0,true,true,false,NULL,true);

INSERT INTO skills (slug,title,tagline,description,category,subcategory,tags,difficulty,price_inr,price_usd,is_free,steps,video_url,video_thumbnail,trending_score,view_count,purchase_count,is_trending,is_new,is_featured,pack_id,published) VALUES (
'ota-update-pipeline','OTA Update Pipeline','Atomic over-the-air firmware updates with staged rollout and rollback','Build a /ota/manifest API, implement the ESP32 version-check at boot, use a hash-bucketing function for staged rollout percentages, and leverage the ESP32 A/B partition table for safe rollback.','iot',NULL,
ARRAY['ota','firmware','devops'],'advanced',299900,2900,false,
'[{"number":1,"title":"Version manifest endpoint","description":"Serve the latest firmware metadata including download URL and SHA-256 checksum.","code":"app.get(\"/ota/manifest\",async(req,res)=>{\n  const {device_id,current_version}=req.query;\n  const latest=await db.query(\"SELECT * FROM firmware_releases WHERE channel=$1 ORDER BY created_at DESC LIMIT 1\",[\"stable\"]);\n  res.json({current:current_version,latest:latest.version,url:latest.download_url,sha256:latest.checksum});\n});","language":"typescript"},{"number":2,"title":"ESP32 OTA check at boot","description":"On every boot compare the running version against the manifest and trigger OTA if behind.","code":"HTTPClient http;\nhttp.begin(\"https://api.yourdomain.com/ota/manifest?device_id=\"+deviceId+\"&current_version=\"+FIRMWARE_VERSION);\nDynamicJsonDocument doc(512);\ndeserializeJson(doc,http.getString());\nif(doc[\"latest\"].as<String>()!=FIRMWARE_VERSION)performOTA(doc[\"url\"],doc[\"sha256\"]);","language":"cpp"},{"number":3,"title":"Staged rollout logic","description":"Deterministically assign each device to a 0-100 bucket using its ID hash.","code":"function shouldReceiveUpdate(deviceId:string,rolloutPercent:number):boolean{\n  const hash=crypto.createHash(\"md5\").update(deviceId).digest(\"hex\");\n  const bucket=parseInt(hash.slice(0,2),16)/255*100;\n  return bucket<=rolloutPercent;\n}","language":"typescript"},{"number":4,"title":"Rollback on failure","description":"Use the ESP32 A/B OTA partition table so a failed update automatically boots the previous slot.","code":"const esp_partition_t* update=esp_ota_get_next_update_partition(NULL);\nesp_ota_handle_t handle;\nesp_ota_begin(update,OTA_SIZE_UNKNOWN,&handle);\n// ... write chunks ...\nesp_ota_end(handle);\nesp_ota_set_boot_partition(update);","language":"cpp"}]'::jsonb,
NULL,NULL,760,0,0,true,true,false,NULL,true);

INSERT INTO skills (slug,title,tagline,description,category,subcategory,tags,difficulty,price_inr,price_usd,is_free,steps,video_url,video_thumbnail,trending_score,view_count,purchase_count,is_trending,is_new,is_featured,pack_id,published) VALUES (
'lorawan-device-setup','LoRaWAN Device Setup','Register and activate LoRaWAN devices on TTN/Chirpstack step by step','Provision OTAA keys, register the device on TTN via CLI, write a binary payload decoder, and forward uplinks to TimescaleDB via a webhook handler.','iot',NULL,
ARRAY['lorawan','ttn','iot'],'intermediate',199900,1900,false,
'[{"number":1,"title":"Generate DevEUI and keys","description":"Hardcode APPEUI, DEVEUI, and APPKEY in PROGMEM for OTAA activation.","code":"static const u1_t PROGMEM APPEUI[8]={0x00,0x00,0x00,0x00,0x00,0x00,0x00,0x00};\nstatic const u1_t PROGMEM DEVEUI[8]={0x01,0x23,0x45,0x67,0x89,0xAB,0xCD,0xEF};\nstatic const u1_t PROGMEM APPKEY[16]={0x2B,0x7E,0x15,0x16,0x28,0xAE,0xD2,0xA6,0xAB,0xF7,0x15,0x88,0x09,0xCF,0x4F,0x3C};","language":"cpp"},{"number":2,"title":"Register on TTN via CLI","description":"Create the end-device on The Things Network using ttn-lw-cli.","code":"ttn-lw-cli end-devices create --application-id my-app \\\n  --device-id my-device \\\n  --dev-eui 0123456789ABCDEF \\\n  --join-eui 0000000000000000 \\\n  --lorawan-version 1.0.3 \\\n  --frequency-plan-id EU_863_870_TTN","language":"bash"},{"number":3,"title":"Decode binary payload","description":"Parse a 4-byte payload into temperature, humidity, and battery voltage.","code":"function decodePayload(bytes:number[]){\n  const temp=(bytes[0]!<<8|bytes[1]!)/100;\n  const humidity=bytes[2]!/2;\n  const battery=(bytes[3]!+200)/100;\n  return{temp,humidity,battery};\n}","language":"typescript"},{"number":4,"title":"Forward uplinks to TimescaleDB","description":"Receive TTN webhook POSTs and insert decoded sensor values into the hypertable.","code":"app.post(\"/ttn/webhook\",async(req,res)=>{\n  const{device_id,decoded_payload,received_at}=req.body.uplink_message;\n  await db.query(\"INSERT INTO sensor_readings VALUES($1,$2,$3,$4)\",\n    [received_at,device_id,\"temp\",decoded_payload.temp]);\n  res.sendStatus(200);\n});","language":"typescript"}]'::jsonb,
NULL,NULL,580,0,0,true,true,false,NULL,true);

INSERT INTO skills (slug,title,tagline,description,category,subcategory,tags,difficulty,price_inr,price_usd,is_free,steps,video_url,video_thumbnail,trending_score,view_count,purchase_count,is_trending,is_new,is_featured,pack_id,published) VALUES (
'modbus-rtu-driver','Modbus RTU Driver','Read and write Modbus RTU/TCP registers from Node.js or C','Connect to a serial Modbus slave, read holding registers, write coils and registers, and poll on a 5-second interval with error recovery.','iot',NULL,
ARRAY['modbus','industrial','protocols'],'advanced',299900,2900,false,
'[{"number":1,"title":"Install modbus-serial","description":"Add the modbus-serial npm package to your Node.js project.","code":"npm install modbus-serial","language":"bash"},{"number":2,"title":"Read holding registers","description":"Open the serial port and read 10 consecutive holding registers from slave ID 1.","code":"import ModbusRTU from \"modbus-serial\";\nconst client=new ModbusRTU();\nawait client.connectRTUBuffered(\"/dev/ttyUSB0\",{baudRate:9600,dataBits:8,parity:\"none\",stopBits:1});\nclient.setID(1);\nconst data=await client.readHoldingRegisters(0,10);\nconsole.log(data.data);","language":"typescript"},{"number":3,"title":"Write coils and registers","description":"Toggle a coil, write a single register, and write a block of registers in one sequence.","code":"await client.writeCoil(0,true);\nawait client.writeRegister(10,1234);\nawait client.writeRegisters(20,[100,200,300]);","language":"typescript"},{"number":4,"title":"Poll and store with error handling","description":"Read current, voltage, and power every 5 seconds and insert into the database.","code":"setInterval(async()=>{\n  try{\n    const regs=await client.readHoldingRegisters(0,5);\n    const[current,voltage,power]=regs.data;\n    await db.insert({time:new Date(),current,voltage,power});\n  }catch(e){console.error(\"Modbus read error\",e);}\n},5000);","language":"typescript"}]'::jsonb,
NULL,NULL,540,0,0,true,true,false,NULL,true);

INSERT INTO skills (slug,title,tagline,description,category,subcategory,tags,difficulty,price_inr,price_usd,is_free,steps,video_url,video_thumbnail,trending_score,view_count,purchase_count,is_trending,is_new,is_featured,pack_id,published) VALUES (
'edge-ai-tflite-setup','Edge AI with TFLite','Deploy TensorFlow Lite models on ESP32/Raspberry Pi for on-device inference','Convert a Keras model to quantized TFLite, embed it as a C array, run inference on the ESP32 using TFLite Micro, and benchmark the inference latency.','iot',NULL,
ARRAY['tflite','edge-ai','esp32'],'advanced',299900,2900,false,
'[{"number":1,"title":"Convert model to TFLite","description":"Load a Keras model and convert it to a quantized TFLite flatbuffer.","code":"import tensorflow as tf\nmodel=tf.keras.models.load_model(\"model.h5\")\nconverter=tf.lite.TFLiteConverter.from_keras_model(model)\nconverter.optimizations=[tf.lite.Optimize.DEFAULT]\ntflite_model=converter.convert()\nopen(\"model.tflite\",\"wb\").write(tflite_model)","language":"python"},{"number":2,"title":"Convert to C array","description":"Use xxd to produce a C source file that embeds the model bytes.","code":"xxd -i model.tflite > model_data.cc","language":"bash"},{"number":3,"title":"ESP32 inference code","description":"Allocate the tensor arena, load the model, set input, invoke, and read output.","code":"#include \"tensorflow/lite/micro/micro_interpreter.h\"\n#include \"model_data.h\"\nconstexpr int kTensorArenaSize=50*1024;\nuint8_t tensor_arena[kTensorArenaSize];\ntflite::MicroInterpreter interpreter(model,resolver,tensor_arena,kTensorArenaSize);\ninterpreter.AllocateTensors();\ninterpreter.input(0)->data.f[0]=sensorValue;\ninterpreter.Invoke();\nfloat result=interpreter.output(0)->data.f[0];","language":"cpp"},{"number":4,"title":"Benchmark inference time","description":"Wrap the Invoke call with micros() to measure inference latency in microseconds.","code":"unsigned long start=micros();\ninterpreter.Invoke();\nunsigned long elapsed=micros()-start;\nSerial.printf(\"Inference: %luus (%.1fms)\\n\",elapsed,elapsed/1000.0);","language":"cpp"}]'::jsonb,
NULL,NULL,720,0,0,true,true,false,NULL,true);

INSERT INTO skills (slug,title,tagline,description,category,subcategory,tags,difficulty,price_inr,price_usd,is_free,steps,video_url,video_thumbnail,trending_score,view_count,purchase_count,is_trending,is_new,is_featured,pack_id,published) VALUES (
'iot-security-hardening','IoT Security Hardening','Secure boot, encrypted storage, mTLS and certificate pinning for ESP32','Enable secure boot V2 and flash encryption via sdkconfig, store secrets in encrypted NVS, configure mTLS with client certificates, and add connection-failure backoff with deep sleep.','iot',NULL,
ARRAY['security','esp32','tls'],'advanced',299900,2900,false,
'[{"number":1,"title":"Enable secure boot","description":"Configure secure boot V2 in sdkconfig and generate the signing key.","code":"# sdkconfig\nCONFIG_SECURE_BOOT=y\nCONFIG_SECURE_BOOT_SIGNING_KEY=\"secure_boot_signing_key.pem\"\nCONFIG_SECURE_SIGNED_ON_BOOT=y\n# Generate key:\nespsecure.py generate_signing_key --version 2 secure_boot_signing_key.pem","language":"bash"},{"number":2,"title":"Flash encryption and encrypted NVS","description":"Enable flash encryption in development mode; NVS stores all secrets encrypted at rest.","code":"// sdkconfig\nCONFIG_FLASH_ENCRYPTION_ENABLED=y\nCONFIG_FLASH_ENCRYPTION_MODE_DEVELOPMENT=y\n// In firmware:\nnvs_flash_init();\nnvs_open(\"storage\",NVS_READWRITE,&nvs);\nnvs_set_str(nvs,\"api_key\",apiKey);","language":"cpp"},{"number":3,"title":"mTLS certificate pinning","description":"Load the server CA, client certificate, and private key into WiFiClientSecure for mutual TLS.","code":"WiFiClientSecure net;\nnet.setCACert(root_ca);\nnet.setCertificate(client_cert);\nnet.setPrivateKey(client_key);\nmqttClient.begin(\"broker.yourdomain.com\",8883,net);","language":"cpp"},{"number":4,"title":"Connection failure backoff","description":"Count consecutive MQTT failures in NVS and deep-sleep for 5 minutes after 5 failures.","code":"static int failCount=0;\nif(!mqtt.connected()){failCount++;\n  if(failCount>5){\n    nvs_set_u32(nvs,\"fail_count\",failCount);\n    esp_deep_sleep(300000000ULL);\n  }\n}else{failCount=0;}","language":"cpp"}]'::jsonb,
NULL,NULL,660,0,0,true,true,false,NULL,true);

INSERT INTO skills (slug,title,tagline,description,category,subcategory,tags,difficulty,price_inr,price_usd,is_free,steps,video_url,video_thumbnail,trending_score,view_count,purchase_count,is_trending,is_new,is_featured,pack_id,published) VALUES (
'canbus-decoder','CAN Bus Decoder','Parse and log CAN bus messages from vehicles or industrial equipment','Wire an MCP2515 to ESP32 over SPI, read CAN frames in the loop, decode OBD-II PIDs for RPM, speed, and coolant, then forward frames as JSON over MQTT.','iot',NULL,
ARRAY['canbus','automotive','industrial'],'advanced',299900,2900,false,
'[{"number":1,"title":"Connect MCP2515 to ESP32","description":"Initialise the MCP2515 SPI CAN controller at 500 kbps in normal mode.","code":"#include <mcp_can.h>\nMCP_CAN CAN(5); // CS=GPIO5\nvoid setup(){\n  CAN.begin(MCP_ANY,500000,MCP_8MHZ);\n  CAN.setMode(MCP_NORMAL);\n}","language":"cpp"},{"number":2,"title":"Read and decode frames","description":"Poll for available messages and print the ID and hex data bytes.","code":"long unsigned int rxId;\nunsigned char len,buf[8];\nif(CAN_MSGAVAIL==CAN.checkReceive()){\n  CAN.readMsgBuf(&rxId,&len,buf);\n  Serial.printf(\"ID: 0x%03X Len:%d \",rxId,len);\n  for(int i=0;i<len;i++)Serial.printf(\"%02X \",buf[i]);\n}","language":"cpp"},{"number":3,"title":"Decode OBD-II PIDs","description":"Implement helper functions for the most common OBD-II PIDs.","code":"float decodeRPM(uint8_t* buf){return((buf[0]*256.0+buf[1])/4.0);}\nfloat decodeSpeed(uint8_t* buf){return buf[0];}\nfloat decodeCoolantTemp(uint8_t* buf){return buf[0]-40;}\n// PID 0x0C=RPM, 0x0D=Speed, 0x05=Coolant","language":"cpp"},{"number":4,"title":"Publish frames as JSON over MQTT","description":"Serialise each frame as JSON and publish to the /can/frames topic.","code":"String json=\"{\\\"ts\\\":\"+String(millis())+\",\\\"id\\\":\\\"\"+String(rxId,HEX)+\"\\\",\\\"data\\\":[\"+dataStr+\"]}\";\nmqtt.publish(\"/can/frames\",json.c_str());","language":"cpp"}]'::jsonb,
NULL,NULL,500,0,0,true,true,false,NULL,true);

INSERT INTO skills (slug,title,tagline,description,category,subcategory,tags,difficulty,price_inr,price_usd,is_free,steps,video_url,video_thumbnail,trending_score,view_count,purchase_count,is_trending,is_new,is_featured,pack_id,published) VALUES (
'zigbee-mesh-planner','Zigbee Mesh Planner','Design Zigbee mesh topology, device roles and network addressing','Plan coordinator, router, and end-device counts, configure Zigbee2MQTT with the right channel and PAN ID to avoid WiFi overlap, pair devices, and write an occupancy automation rule.','iot',NULL,
ARRAY['zigbee','mesh','iot'],'intermediate',199900,1900,false,
'[{"number":1,"title":"Device role planning","description":"Define coordinator, router, and end-device counts and placement strategy.","code":"const network={\n  coordinator:{count:1,device:\"CC2652P\",role:\"collects all data, connects to server\"},\n  routers:{count:4,device:\"SONOFF ZBMINI\",placement:\"spread for 15m coverage per hop\"},\n  endDevices:{count:20,device:\"Xiaomi sensors\",battery:\"AA, 2yr life\"}\n};","language":"typescript"},{"number":2,"title":"PANID and channel setup","description":"Configure Zigbee2MQTT to use channel 25 to avoid overlap with WiFi channels 1, 6, and 11.","code":"# config.yaml\npermit_join: true\nmqtt:\n  base_topic: zigbee2mqtt\n  server: mqtt://localhost\nserial:\n  port: /dev/ttyACM0\nadvanced:\n  pan_id: 0x1234\n  channel: 25","language":"yaml"},{"number":3,"title":"Pair devices","description":"Open a 2-minute pairing window via MQTT and monitor for join events.","code":"mosquitto_pub -t zigbee2mqtt/bridge/request/permit_join -m ''{\"value\":true,\"time\":120}''\n# Hold device button 5s until LED blinks\nmosquitto_sub -t zigbee2mqtt/# -v | grep device_joined","language":"bash"},{"number":4,"title":"Occupancy automation rule","description":"Subscribe to the sensor topic and turn a light ON whenever occupancy is detected.","code":"mosquitto_sub -t \"zigbee2mqtt/sensor_1\" | jq -r ''.occupancy'' | while read state; do\n  if [ \"$state\" = \"true\" ]; then\n    mosquitto_pub -t \"zigbee2mqtt/light_1/set\" -m ''{\"state\":\"ON\"}''\n  fi\ndone","language":"bash"}]'::jsonb,
NULL,NULL,480,0,0,true,true,false,NULL,true);

INSERT INTO skills (slug,title,tagline,description,category,subcategory,tags,difficulty,price_inr,price_usd,is_free,steps,video_url,video_thumbnail,trending_score,view_count,purchase_count,is_trending,is_new,is_featured,pack_id,published) VALUES (
'digital-twin-schema','Digital Twin Schema','Design PostgreSQL + TimescaleDB schema for industrial digital twins','Model assets with typed spec JSONB, ingest real-time telemetry into a partitioned hypertable, track alerts with severity levels, and surface health KPIs in a live view.','iot',NULL,
ARRAY['digital-twin','timescaledb','industrial'],'advanced',299900,2900,false,
'[{"number":1,"title":"Asset model","description":"Create the assets table with manufacturer details, install date, and a spec JSONB column for rated parameters.","code":"CREATE TABLE assets(\n  id            UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n  asset_type    TEXT NOT NULL,\n  serial_number TEXT UNIQUE NOT NULL,\n  manufacturer  TEXT,\n  model         TEXT,\n  install_date  DATE,\n  location      JSONB,\n  spec          JSONB\n);","language":"sql"},{"number":2,"title":"Real-time telemetry hypertable","description":"Create a telemetry hypertable partitioned by time and asset_id for parallel scans.","code":"CREATE TABLE telemetry(\n  time      TIMESTAMPTZ      NOT NULL,\n  asset_id  UUID REFERENCES assets(id),\n  metric    TEXT             NOT NULL,\n  value     DOUBLE PRECISION NOT NULL,\n  quality   SMALLINT         DEFAULT 192\n);\nSELECT create_hypertable(''telemetry'',''time'',partitioning_column=>''asset_id'',number_partitions=>4);","language":"sql"},{"number":3,"title":"Anomaly alerts table","description":"Store triggered alerts with severity, actual value, threshold, and resolution timestamp.","code":"CREATE TABLE alerts(\n  id           UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n  asset_id     UUID REFERENCES assets(id),\n  metric       TEXT NOT NULL,\n  severity     TEXT CHECK(severity IN(''info'',''warning'',''critical'')),\n  value        DOUBLE PRECISION,\n  threshold    DOUBLE PRECISION,\n  triggered_at TIMESTAMPTZ DEFAULT now(),\n  resolved_at  TIMESTAMPTZ\n);","language":"sql"},{"number":4,"title":"Asset health view","description":"Join assets, last-hour telemetry, and recent critical alerts into a single health view.","code":"CREATE VIEW asset_health AS\nSELECT a.id,a.serial_number,a.asset_type,\n  AVG(t.value) FILTER(WHERE t.metric=''vibration'') AS avg_vibration,\n  MAX(t.value) FILTER(WHERE t.metric=''temperature'') AS max_temp,\n  COUNT(al.id) FILTER(WHERE al.severity=''critical'' AND al.triggered_at>now()-INTERVAL''7d'') AS critical_alerts_7d\nFROM assets a\nLEFT JOIN telemetry t ON a.id=t.asset_id AND t.time>now()-INTERVAL''1h''\nLEFT JOIN alerts al ON a.id=al.asset_id\nGROUP BY a.id,a.serial_number,a.asset_type;","language":"sql"}]'::jsonb,
NULL,NULL,620,0,0,true,true,false,NULL,true);

