INSERT INTO skills (slug,title,tagline,description,category,subcategory,tags,difficulty,price_inr,price_usd,is_free,steps,video_url,video_thumbnail,trending_score,view_count,purchase_count,is_trending,is_new,is_featured,pack_id,published) VALUES (
'code-reviewer','Code Reviewer','Security-focused AI code review: OWASP top 10, type safety, performance','Run an AI-powered review that catches SQL injection, N+1 queries, and unsafe any usage in seconds. Integrate into CI to block issues before they reach production.','developer-tools',NULL,
ARRAY['code-review','security','typescript'],'beginner',0,0,true,
'[{"number":1,"title":"Run against a file","description":"Point the CLI at any TypeScript source file to get an instant review.","code":"npx @addonweb/claude-toolkit review ./src/api/auth.ts","language":"bash"},{"number":2,"title":"Review output structure","description":"The tool returns structured JSON with categorised findings and a quality score.","code":"// Output:\n{\n  security:  [{severity:\"high\",issue:\"SQL injection\",line:45,fix:\"Use parameterized queries\"}],\n  performance:[{issue:\"N+1 query\",line:78,fix:\"Add eager loading\"}],\n  types:     [{issue:\"any usage\",line:12,fix:\"Replace with specific type\"}],\n  score: 7.2\n}","language":"typescript"},{"number":3,"title":"Apply a fix","description":"Compare the vulnerable pattern against the parameterised-query safe version.","code":"// Before (vulnerable):\nconst user=await db.query(`SELECT * FROM users WHERE id=${userId}`);\n// After (safe):\nconst user=await db.query(\"SELECT * FROM users WHERE id=$1\",[userId]);","language":"typescript"},{"number":4,"title":"Run in CI","description":"Add the review step to GitHub Actions and fail the build on medium-severity or above.","code":"# .github/workflows/review.yml\n- name: AI Code Review\n  run: npx @addonweb/claude-toolkit review ./src --format=github-comment --min-severity=medium","language":"yaml"}]'::jsonb,
NULL,NULL,950,0,0,true,true,true,NULL,true);

INSERT INTO skills (slug,title,tagline,description,category,subcategory,tags,difficulty,price_inr,price_usd,is_free,steps,video_url,video_thumbnail,trending_score,view_count,purchase_count,is_trending,is_new,is_featured,pack_id,published) VALUES (
'sql-query-builder','SQL Query Builder','Write SQL in plain English — handles JOINs, CTEs, window functions','Describe what you need in plain language, get production-ready PostgreSQL back, refine with follow-up instructions, and execute directly from your codebase.','developer-tools',NULL,
ARRAY['sql','natural-language','postgresql'],'beginner',0,0,true,
'[{"number":1,"title":"Describe your query","description":"Pass a plain-English description plus your table schema to the skill.","code":"const result=await runSkill(sqlQueryBuilder,{\n  description:\"Get top 10 customers by revenue in the last 30 days with their order count\",\n  schema:\"customers(id,name,email), orders(id,customer_id,total,created_at)\",\n  dialect:\"postgresql\"\n});","language":"typescript"},{"number":2,"title":"Get generated SQL","description":"The skill returns valid, formatted SQL ready to paste or execute.","code":"SELECT c.name,c.email,COUNT(o.id) AS order_count,SUM(o.total) AS revenue\nFROM customers c\nJOIN orders o ON c.id=o.customer_id\nWHERE o.created_at>=NOW()-INTERVAL ''30 days''\nGROUP BY c.id,c.name,c.email\nORDER BY revenue DESC\nLIMIT 10;","language":"sql"},{"number":3,"title":"Iterate with a follow-up","description":"Refine the previous query using plain-English instructions without rewriting from scratch.","code":"const refined=await runSkill(sqlQueryBuilder,{\n  description:\"Same query but include customers with no orders (show 0s)\",\n  previousQuery:result.data.sql,\n  schema:\"customers(id,name,email), orders(id,customer_id,total,created_at)\"\n});","language":"typescript"},{"number":4,"title":"Run and validate","description":"Execute the generated query and log the row count and duration.","code":"const rows=await db.query(result.data.sql);\nconsole.log(`Returned ${rows.length} rows in ${rows.duration}ms`);","language":"typescript"}]'::jsonb,
NULL,NULL,900,0,0,true,true,true,NULL,true);

INSERT INTO skills (slug,title,tagline,description,category,subcategory,tags,difficulty,price_inr,price_usd,is_free,steps,video_url,video_thumbnail,trending_score,view_count,purchase_count,is_trending,is_new,is_featured,pack_id,published) VALUES (
'test-generator','Test Generator','Generate unit and integration tests from source code automatically','Feed source code to the skill and get a complete Vitest test suite covering happy paths, edge cases, and error handling — ready to run with zero edits.','developer-tools',NULL,
ARRAY['testing','vitest','jest'],'beginner',0,0,true,
'[{"number":1,"title":"Point at a function","description":"Pass the raw source file and specify the desired coverage categories.","code":"const tests=await runSkill(testGenerator,{\n  code:fs.readFileSync(\"./src/lib/pricing.ts\",\"utf8\"),\n  framework:\"vitest\",\n  coverage:[\"happy-path\",\"edge-cases\",\"error-handling\"]\n});","language":"typescript"},{"number":2,"title":"Generated test output","description":"The skill returns a complete describe block with typed imports and assertions.","code":"import{describe,it,expect}from\"vitest\";\nimport{calculateTotal}from\"../lib/pricing\";\ndescribe(\"calculateTotal\",()=>{\n  it(\"applies GST correctly\",()=>expect(calculateTotal(1000,18)).toBe(1180));\n  it(\"handles zero amount\",()=>expect(calculateTotal(0,18)).toBe(0));\n  it(\"throws on negative amount\",()=>expect(()=>calculateTotal(-100,18)).toThrow());\n});","language":"typescript"},{"number":3,"title":"Run tests","description":"Execute the test suite with coverage reporting.","code":"npx vitest run --coverage","language":"bash"},{"number":4,"title":"Add to CI","description":"Wire test and coverage scripts into package.json for CI consumption.","code":"// package.json\n\"scripts\":{\"test\":\"vitest run\",\"test:coverage\":\"vitest run --coverage\"}","language":"json"}]'::jsonb,
NULL,NULL,870,0,0,true,true,false,NULL,true);

INSERT INTO skills (slug,title,tagline,description,category,subcategory,tags,difficulty,price_inr,price_usd,is_free,steps,video_url,video_thumbnail,trending_score,view_count,purchase_count,is_trending,is_new,is_featured,pack_id,published) VALUES (
'docker-compose-builder','Docker Compose Builder','Generate production-ready docker-compose.yml from service descriptions','Describe your stack and the skill returns a compose file with health checks, named volumes, isolated networks, and env-file wiring — no boilerplate hunting.','developer-tools',NULL,
ARRAY['docker','devops','containers'],'beginner',0,0,true,
'[{"number":1,"title":"Describe your stack","description":"List your services and the features you need in the generated file.","code":"const result=await runSkill(dockerComposeBuilder,{\n  services:[\"nextjs-app\",\"postgresql\",\"redis\",\"nginx\"],\n  environment:\"production\",\n  features:[\"health-checks\",\"volumes\",\"networks\",\"env-files\"]\n});","language":"typescript"},{"number":2,"title":"Generated compose file","description":"The skill returns a complete docker-compose.yml with correct dependency ordering.","code":"services:\n  app:\n    build: .\n    env_file: .env\n    depends_on:\n      db:\n        condition: service_healthy\n    networks: [backend]\n  db:\n    image: postgres:16\n    healthcheck:\n      test: [\"CMD\",\"pg_isready\",\"-U\",\"postgres\"]\n      interval: 10s\n    volumes: [postgres_data:/var/lib/postgresql/data]","language":"yaml"},{"number":3,"title":"Start services","description":"Bring the stack up in detached mode and tail app logs.","code":"docker compose up -d\ndocker compose logs -f app","language":"bash"},{"number":4,"title":"Production checklist","description":"Verify no unnecessary ports are exposed and scan images for CVEs.","code":"docker compose config | grep \"ports:\"\ndocker scout cves myapp:latest","language":"bash"}]'::jsonb,
NULL,NULL,780,0,0,true,true,false,NULL,true);

INSERT INTO skills (slug,title,tagline,description,category,subcategory,tags,difficulty,price_inr,price_usd,is_free,steps,video_url,video_thumbnail,trending_score,view_count,purchase_count,is_trending,is_new,is_featured,pack_id,published) VALUES (
'github-actions-pipeline','GitHub Actions Pipeline','CI/CD pipeline: lint, test, build, deploy to Vercel/Railway/Fly','Create a full GitHub Actions workflow that runs type-check, lint, and tests on every PR, then deploys to Vercel production on merge to main.','developer-tools',NULL,
ARRAY['github-actions','ci-cd','devops'],'intermediate',99900,900,false,
'[{"number":1,"title":"Create workflow file","description":"Scaffold the workflow file triggered on push to main and dev and on all PRs.","code":"mkdir -p .github/workflows\ncat > .github/workflows/ci.yml << ''EOF''\nname: CI\non:\n  push:\n    branches: [main,dev]\n  pull_request:\n    branches: [main]\nEOF","language":"bash"},{"number":2,"title":"Lint and test job","description":"Set up Node 20 with npm cache, then run lint, type-check, and tests with coverage.","code":"jobs:\n  test:\n    runs-on: ubuntu-latest\n    steps:\n      - uses: actions/checkout@v4\n      - uses: actions/setup-node@v4\n        with: {node-version: \"20\", cache: \"npm\"}\n      - run: npm ci\n      - run: npm run lint\n      - run: npm run type-check\n      - run: npm test -- --coverage","language":"yaml"},{"number":3,"title":"Deploy to Vercel on main","description":"Use the official Vercel action to deploy to production only when tests pass on main.","code":"  deploy:\n    needs: test\n    if: github.ref==''refs/heads/main''\n    runs-on: ubuntu-latest\n    steps:\n      - uses: actions/checkout@v4\n      - uses: amondnet/vercel-action@v25\n        with:\n          vercel-token: ${{secrets.VERCEL_TOKEN}}\n          vercel-org-id: ${{secrets.VERCEL_ORG_ID}}\n          vercel-project-id: ${{secrets.VERCEL_PROJECT_ID}}\n          vercel-args: ''--prod''","language":"yaml"},{"number":4,"title":"Add status badge","description":"Paste the workflow badge into your README for instant build-status visibility.","code":"[![CI](https://github.com/org/repo/actions/workflows/ci.yml/badge.svg)](https://github.com/org/repo/actions/workflows/ci.yml)","language":"markdown"}]'::jsonb,
NULL,NULL,820,0,0,true,true,false,NULL,true);

INSERT INTO skills (slug,title,tagline,description,category,subcategory,tags,difficulty,price_inr,price_usd,is_free,steps,video_url,video_thumbnail,trending_score,view_count,purchase_count,is_trending,is_new,is_featured,pack_id,published) VALUES (
'database-migration-planner','Database Migration Planner','Plan safe zero-downtime schema migrations for production PostgreSQL','Analyse table sizes, add columns without locking, create indexes concurrently, and check for long-running queries before executing any DDL.','developer-tools',NULL,
ARRAY['postgresql','migrations','devops'],'advanced',199900,1900,false,
'[{"number":1,"title":"Analyse existing schema","description":"Query pg_stat_user_tables to understand table sizes and row counts before planning DDL.","code":"SELECT schemaname,tablename,\n  pg_size_pretty(pg_total_relation_size(schemaname||''.''||tablename)) AS size,\n  n_live_tup AS row_count\nFROM pg_stat_user_tables\nORDER BY pg_total_relation_size(schemaname||''.''||tablename) DESC;","language":"sql"},{"number":2,"title":"Add column safely","description":"In PG11+ ADD COLUMN with a DEFAULT is instant. For NOT NULL columns backfill before adding the constraint.","code":"-- Safe on large tables:\nALTER TABLE users ADD COLUMN IF NOT EXISTS preferences JSONB DEFAULT ''{}'';\n-- NOT NULL pattern:\nALTER TABLE users ADD COLUMN phone TEXT;\nUPDATE users SET phone='''' WHERE phone IS NULL;\nALTER TABLE users ALTER COLUMN phone SET NOT NULL;","language":"sql"},{"number":3,"title":"Create index without blocking writes","description":"CONCURRENTLY builds the index without holding an exclusive lock on the table.","code":"CREATE INDEX CONCURRENTLY IF NOT EXISTS idx_users_email ON users(email);\nCREATE INDEX CONCURRENTLY IF NOT EXISTS idx_orders_customer\n  ON orders(customer_id) WHERE status!=''deleted'';","language":"sql"},{"number":4,"title":"Check for conflicting queries","description":"Confirm no long-running transactions will conflict with your DDL before deploying.","code":"SELECT pid,now()-query_start AS duration,query\nFROM pg_stat_activity\nWHERE state=''active'' AND query_start<now()-INTERVAL ''30 seconds''\nORDER BY duration DESC;","language":"sql"}]'::jsonb,
NULL,NULL,640,0,0,true,true,false,NULL,true);

INSERT INTO skills (slug,title,tagline,description,category,subcategory,tags,difficulty,price_inr,price_usd,is_free,steps,video_url,video_thumbnail,trending_score,view_count,purchase_count,is_trending,is_new,is_featured,pack_id,published) VALUES (
'api-docs-generator','API Docs Generator','Generate OpenAPI 3.0 spec and markdown docs from your route handlers','Point the skill at your Next.js or Fastify route files and get a complete OpenAPI 3.0 spec, a Swagger/Redoc UI endpoint, and a generated TypeScript client SDK.','developer-tools',NULL,
ARRAY['openapi','swagger','documentation'],'beginner',99900,900,false,
'[{"number":1,"title":"Point at route files","description":"Pass a glob of route files plus API metadata to the skill.","code":"const spec=await runSkill(apiDocsGenerator,{\n  routeFiles:[\"src/app/api/**/*.ts\"],\n  framework:\"nextjs\",\n  title:\"AddonWeb Toolkit API\",\n  version:\"1.0.0\",\n  baseUrl:\"https://addon90days.vercel.app\"\n});","language":"typescript"},{"number":2,"title":"Generated OpenAPI spec","description":"The skill returns a valid OpenAPI 3.0 YAML with paths, parameters, and response schemas.","code":"openapi: \"3.0.0\"\ninfo:\n  title: AddonWeb Toolkit API\n  version: 1.0.0\npaths:\n  /api/skills:\n    get:\n      summary: List skills\n      parameters:\n        - name: category\n          in: query\n          schema: {type: string}\n      responses:\n        \"200\":\n          description: Skills list","language":"yaml"},{"number":3,"title":"Serve with Redoc","description":"Mount the spec as JSON and serve a zero-dependency Redoc page.","code":"app.get(\"/openapi.json\",(_,res)=>res.json(spec));\napp.get(\"/docs\",(_,res)=>res.send(`<html><body><redoc spec-url=''/openapi.json''></redoc><script src=''https://cdn.redoc.ly/redoc/latest/bundles/redoc.standalone.js''></script></body></html>`));","language":"typescript"},{"number":4,"title":"Auto-generate TypeScript client","description":"Use openapi-typescript to generate type-safe client types from the spec.","code":"npx openapi-typescript openapi.json --output src/types/api.d.ts","language":"bash"}]'::jsonb,
NULL,NULL,700,0,0,true,true,false,NULL,true);

INSERT INTO skills (slug,title,tagline,description,category,subcategory,tags,difficulty,price_inr,price_usd,is_free,steps,video_url,video_thumbnail,trending_score,view_count,purchase_count,is_trending,is_new,is_featured,pack_id,published) VALUES (
'regex-builder','Regex Builder','Generate and explain regular expressions from plain English descriptions','Describe the pattern you need, get a regex with step-by-step explanation and test results, then drop it directly into form validation or parsing logic.','developer-tools',NULL,
ARRAY['regex','validation','parsing'],'beginner',0,0,true,
'[{"number":1,"title":"Describe your pattern","description":"Pass a plain-English description and example inputs that should match or fail.","code":"const result=await runSkill(regexBuilder,{\n  description:\"Match Indian mobile numbers: optional +91 or 0, then 10 digits starting with 6-9\",\n  testCases:[\"9876543210\",\"+919876543210\",\"09876543210\",\"1234567890\"]\n});","language":"typescript"},{"number":2,"title":"Get pattern and explanation","description":"The skill returns the regex and a line-by-line explanation of each component.","code":"{\n  pattern: /^(?:\\+91|0)?[6-9]\\d{9}$/,\n  explanation: [\n    \"^ - start of string\",\n    \"(?:\\\\+91|0)? - optional +91 or 0 prefix\",\n    \"[6-9] - first digit must be 6,7,8, or 9\",\n    \"\\\\d{9} - exactly 9 more digits\",\n    \"$ - end of string\"\n  ],\n  testResults:{pass:3,fail:1}\n}","language":"typescript"},{"number":3,"title":"Use in form validation","description":"Drop the pattern into a typed validation function that strips spaces and dashes.","code":"const indianMobile=/^(?:\\+91|0)?[6-9]\\d{9}$/;\nfunction validatePhone(phone:string):boolean{\n  return indianMobile.test(phone.replace(/[\\s-]/g,\"\"));\n}","language":"typescript"},{"number":4,"title":"Unit test","description":"Write Vitest assertions covering valid numbers and known invalid inputs.","code":"import{expect,test}from\"vitest\";\ntest(\"valid Indian mobiles\",()=>{\n  expect(validatePhone(\"9876543210\")).toBe(true);\n  expect(validatePhone(\"+91 98765 43210\")).toBe(true);\n  expect(validatePhone(\"1234567890\")).toBe(false);\n});","language":"typescript"}]'::jsonb,
NULL,NULL,760,0,0,true,true,false,NULL,true);

