'error-debugger','Error Debugger','Paste a stack trace, get root cause analysis and fix in 30 seconds','Feed a stack trace and source context to the skill and get back the root cause, the affected line, a ready-to-apply code fix, and a prevention tip.','developer-tools',NULL,
ARRAY['debugging','errors','productivity'],'beginner',0,0,true,
'[{"number":1,"title":"Paste your error","description":"Pass the full stack trace and the relevant source file to the skill.","code":"const analysis=await runSkill(errorDebugger,{\n  stackTrace:`TypeError: Cannot read properties of undefined (reading ''map'')\n    at UserList (src/components/UserList.tsx:23:18)`,\n  codeContext:fs.readFileSync(\"src/components/UserList.tsx\",\"utf8\")\n});","language":"typescript"},{"number":2,"title":"Get root cause and fix","description":"The skill returns a structured object with root cause, line number, fix, and prevention advice.","code":"{\n  rootCause: \"users prop is undefined on first render before data loads\",\n  line: 23,\n  fix: \"Add null check: (users ?? []).map(...) or add loading state\",\n  codeFix: \"const list=users?.map(u=><UserRow key={u.id} user={u}/>)??<Spinner/>\",\n  prevention: \"Define default prop value: users: User[] = []\"\n}","language":"typescript"},{"number":3,"title":"Apply the fix","description":"Swap the unsafe map call for the null-safe version with a loading fallback.","code":"// Before:\nreturn users.map(user=><UserCard key={user.id} user={user}/>);\n// After:\nif(!users)return <Skeleton/>;\nreturn users.map(user=><UserCard key={user.id} user={user}/>);","language":"typescript"},{"number":4,"title":"Catch errors in pre-commit","description":"Run TypeScript and ESLint before every commit to surface similar issues early.","code":"npx tsc --noEmit && npx eslint src/ --ext .ts,.tsx","language":"bash"}]'::jsonb,
NULL,NULL,840,0,0,true,true,false,NULL,true);

