'load-test-script-generator','Load Test Script Generator','Generate k6 or Artillery load test scripts from API descriptions','Describe your API endpoints and target scenarios, get a runnable k6 script with ramp-up stages and p95 thresholds, then analyse results in Grafana or k6 Cloud.','developer-tools',NULL,
ARRAY['k6','load-testing','performance'],'intermediate',99900,900,false,
'[{"number":1,"title":"Describe your API","description":"Provide endpoint details and the ramp-up and sustained load scenarios.","code":"const script=await runSkill(loadTestScriptGenerator,{\n  api:{baseUrl:\"https://api.example.com\",endpoints:[{method:\"POST\",path:\"/api/skills/run\",body:{skillId:\"sql-query-builder\"}}]},\n  tool:\"k6\",\n  scenarios:{rampUp:\"0->100 users over 1min\",sustained:\"100 users for 5min\"}\n});","language":"typescript"},{"number":2,"title":"Generated k6 script","description":"The skill returns a complete k6 script with stages and p95 and error-rate thresholds.","code":"import http from \"k6/http\";\nimport{check,sleep}from \"k6\";\nexport const options={\n  stages:[\n    {duration:\"1m\",target:100},\n    {duration:\"5m\",target:100},\n    {duration:\"30s\",target:0}\n  ],\n  thresholds:{\"http_req_duration\":[\"p(95)<500\"],\"http_req_failed\":[\"rate<0.01\"]}\n};","language":"typescript"},{"number":3,"title":"Run the test","description":"Execute locally or stream results to k6 Cloud.","code":"k6 run script.js\n# With cloud output:\nk6 run --out cloud script.js","language":"bash"},{"number":4,"title":"Analyse results","description":"Check the three key metrics to confirm your API meets the SLA.","code":"# Key metrics:\n# http_req_duration p(95) < 500ms\n# http_req_failed rate < 1%\n# Check Grafana dashboard or k6 cloud for per-endpoint flamegraph","language":"bash"}]'::jsonb,
NULL,NULL,580,0,0,true,true,false,NULL,true);

INSERT INTO skills (slug,title,tagline,description,category,subcategory,tags,difficulty,price_inr,price_usd,is_free,steps,video_url,video_thumbnail,trending_score,view_count,purchase_count,is_trending,is_new,is_featured,pack_id,published) VALUES (
'env-var-validator','Env Var Validator','Validate and type-check all environment variables at startup with Zod','Use Zod to parse process.env at boot, surface missing or malformed variables immediately, generate a typed env object, and add a CI check that fails fast on misconfiguration.','developer-tools',NULL,
ARRAY['zod','env','typescript'],'beginner',0,0,true,
'[{"number":1,"title":"Define the schema","description":"Declare every required and optional env var with its expected type and constraints.","code":"import{z}from\"zod\";\nconst envSchema=z.object({\n  DATABASE_URL:z.string().url(),\n  PORT:z.coerce.number().min(1024).max(65535).default(3000),\n  NODE_ENV:z.enum([\"development\",\"test\",\"production\"]),\n  STRIPE_SECRET_KEY:z.string().startsWith(\"sk_\"),\n  RESEND_API_KEY:z.string().optional()\n});","language":"typescript"},{"number":2,"title":"Parse at startup","description":"Call parse once at module load time so the process crashes loudly before serving any requests.","code":"export const env=envSchema.parse(process.env);\n// TypeScript now knows env.PORT is number, env.DATABASE_URL is string, etc.","language":"typescript"},{"number":3,"title":"Surface friendly errors","description":"Catch Zod errors and print a table of every missing or invalid variable before exiting.","code":"const result=envSchema.safeParse(process.env);\nif(!result.success){\n  console.error(\"Invalid environment variables:\");\n  result.error.issues.forEach(i=>console.error(` ${i.path.join(\".\")} — ${i.message}`));\n  process.exit(1);\n}","language":"typescript"},{"number":4,"title":"CI check for .env.example drift","description":"Add a script that parses .env.example through the schema to catch missing keys before deploy.","code":"// scripts/check-env.ts\nimport\"dotenv/config\";\nimport{envSchema}from\"../src/env\";\nconst result=envSchema.safeParse(process.env);\nif(!result.success){console.error(result.error.format());process.exit(1);}\nconsole.log(\"Env OK:\",Object.keys(result.data).length,\"vars validated\");","language":"typescript"}]'::jsonb,
NULL,NULL,690,0,0,true,true,false,NULL,true);

INSERT INTO skills (slug,title,tagline,description,category,subcategory,tags,difficulty,price_inr,price_usd,is_free,steps,video_url,video_thumbnail,trending_score,view_count,purchase_count,is_trending,is_new,is_featured,pack_id,published) VALUES (
'code-refactorer','Code Refactorer','Refactor code for readability, performance and maintainability','Submit messy code with refactoring goals, get a clean diff with named constants, extracted types, and removed duplication — then verify your tests still pass.','developer-tools',NULL,
ARRAY['refactoring','clean-code','typescript'],'intermediate',99900,900,false,
'[{"number":1,"title":"Submit code for review","description":"Pass the raw code and the refactoring goals to the skill.","code":"const result=await runSkill(codeRefactorer,{\n  code:uglyCode,\n  goals:[\"readability\",\"performance\",\"remove-duplication\"],\n  language:\"typescript\"\n});","language":"typescript"},{"number":2,"title":"Before and after diff","description":"The skill highlights the exact changes with named constants replacing magic numbers.","code":"// Before: nested conditionals, magic numbers\nfunction calc(x:number,t:number){if(t===1)return x*0.18;else if(t===2)return x*0.12;return x*0.05;}\n// After: named constants, clear intent\nconst GST_RATES={standard:0.18,reduced:0.12,exempt:0.05} as const;\ntype GSTCategory=keyof typeof GST_RATES;\nfunction calculateGST(amount:number,category:GSTCategory):number{return amount*GST_RATES[category];}","language":"typescript"},{"number":3,"title":"Apply changes","description":"Write the refactored code back to the original file path.","code":"import{writeFileSync}from\"fs\";\nwriteFileSync(filePath,result.data.refactoredCode,\"utf8\");","language":"typescript"},{"number":4,"title":"Verify tests pass","description":"Run the full test suite to confirm the refactor did not change behaviour.","code":"npm test -- --coverage 2>&1 | tail -20","language":"bash"}]'::jsonb,
NULL,NULL,720,0,0,true,true,false,NULL,true);
